/*Table structure for table `student` */

DROP TABLE IF EXISTS `student`;

CREATE TABLE `student` (
  `ID` varchar(10) COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `student_name` varchar(10) COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `ID_card` varchar(18) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `phone_number` varchar(15) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `start_year` year(4) DEFAULT NULL,
  `student_source` varchar(10) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `major` varchar(10) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `class_name` varchar(10) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  PRIMARY KEY (`ID`) USING BTREE,
  KEY `class_name` (`class_name`) USING BTREE,
  CONSTRAINT `student_ibfk_1` FOREIGN KEY (`class_name`) REFERENCES `class_info` (`class_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci ROW_FORMAT=DYNAMIC;

