CREATE TABLE `training_program` (
  `course_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_name` varchar(255) COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `course_nature` varchar(10) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `course_major` varchar(255) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `course_teacher` varchar(10) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `course_attributes` varchar(255) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `preliminary_course` varchar(255) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `followup_course` varchar(255) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  PRIMARY KEY (`course_id`) USING BTREE,
  KEY `id` (`course_id`) USING BTREE
